import { HttpErrorResponse } from '@angular/common/http';
import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';
import { TrnDataMaster } from '../transaction-code-new/transaction-code-new.component';


@Component({
  selector: 'npr-transaction-code-edit',
  templateUrl: './transaction-code-edit.component.html',
  styleUrls: ['./transaction-code-edit.component.scss']
})
export class TransactionCodeEditComponent implements OnInit {
  transactionCodeEditForm: FormGroup;
  showList: boolean = false;
  editFlag: boolean = false;
  disablesubmit: boolean;
  UserId: any;
  userName: any;
  usersList: any;
  masterClass = new TrnDataMaster;
  formValues = {
    trnDesc: '',
    trnCode: ''
  }
  transactionData: Array<TrnData>;
  transactionCodeSummryData: any;
  deleteRowResp: any;
  authResponse: any;
  savetrnResponse: any;
  updatetrnResp: any;
  trnDescp: any;
  trnCod: any;
  currentUser: string;
  submitFlag: boolean = false;
  constructor(private formBuilder: FormBuilder, private apiService: ApiService,
    private toastService: ToastService, private router: Router, private ref: ChangeDetectorRef,) { }

  ngOnInit(): void {
    this.currentUser = localStorage.getItem("userFromLogin");
    this.transactionCodeEditForm = this.formBuilder.group({
      userId: [""],
      transactionData: this.formBuilder.array([this.createtransactionCodeGroup()])
    });
    this.getUserName();
    this.gettingSummaryData();

  }
  private createtransactionCodeGroup(): FormGroup {
    return new FormGroup({
      'trnDesc': new FormControl(''),
      'trnCode': new FormControl('')
    })
  }
  invalidLogin(event: Event) {
    this.submitFlag = true;
  }
  onOptionsSelected(event) {
    const value = event.target.value;
    if (value) {
      this.transactionCodeEditForm.controls.userId.setValue(value);
      this.showList = false;
      console.log(value);
    }
  }
  public removeData(i: number) {
    const transactionData = this.transactionCodeEditForm.get('transactionData') as FormArray
    if (transactionData.length > 1) {
      transactionData.removeAt(i)
    } else {
      transactionData.reset()
    }
  }
  deleteRowData(data) {
    console.log("this.transactionCodeSummryData.formValues", this.transactionCodeSummryData.formValues)
    this.apiService.deleteRow(data.id).subscribe(resp => {
      this.deleteRowResp = resp;
      if (this.deleteRowResp == true) {
        this.submitFlag = true;
        this.removeData(data);
      }
      else {
        Swal.fire({
          title: 'Failed to Delete Row Data!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });
  }
  public addFormGroup() {
    const transactionData = this.transactionCodeEditForm.get('transactionData') as FormArray
    transactionData.push(this.createtransactionCodeGroup())
  }
  getUserName() {
    this.apiService.getUserName().subscribe(userName => {
      this.userName = userName;
      this.usersList = [];
      if (this.userName) {
        console.log(this.userName);
      } else {
        console.log("No name");
      }
    });
  }

  keyPress(user: any) {
    if (user) {
      this.showList = true;
      let list = this.userName.filter(option => option.includes(user));
      this.usersList = list;
    }
    else {
      this.showList = false;
      this.usersList = [];
    }
  }
  gettingSummaryData() {
    this.apiService.getSummaryDataTransactionCode().subscribe((summaryData) => {
      this.transactionCodeSummryData = summaryData;
      console.log("this.transactionCodeSummryData", this.transactionCodeSummryData.formValues);
      this.auditLog();
      const userID = this.transactionCodeSummryData.userID;
      this.transactionCodeEditForm.controls.userId.setValue(userID);
      this.addtrnDec.removeAt(0);
      this.transactionCodeSummryData.formValues.forEach(element => {
        const row = this.formBuilder.group({
          trnDesc: [element.trnDesc, [Validators.required]],
          trnCode: [element.trnCode, [Validators.required]],
          id: [element.id, [Validators.required]],
          userId: [element.userId, [Validators.required]],
          creatorDtStamp: [element.creatorDtStamp, [Validators.required]],
          creatorId: [element.creatorId, [Validators.required]],
          modNo: [element.modNo, [Validators.required]],
          recordStatus: [element.recordStatus, [Validators.required]],
          verifiedBy: [element.verifiedBy, [Validators.required]],
          verifiedOnce: [element.verifiedOnce, [Validators.required]],
          verifiedStatus: [element.verifiedStatus, [Validators.required]],
          verifiedTime: [element.verifiedTime, [Validators.required]],
        });
        this.addtrnDec.push(row);
      });
    });
  }
  get addtrnDec(): FormArray {
    return this.transactionCodeEditForm.get('transactionData') as FormArray;
  }
  enableEditFlag() {
    this.editFlag = true;
  }
  auditLog() {
    if (this.transactionCodeSummryData.verifiedStatus === 'U') {
      this.transactionCodeSummryData.verifiedStatus = 'UNAUTHORIZED'
    }
    if (this.transactionCodeSummryData.verifiedStatus === 'A') {
      this.transactionCodeSummryData.verifiedStatus = 'AUTHORIZED'
    }
    if (this.transactionCodeSummryData.recordStatus === 'O') {
      this.transactionCodeSummryData.recordStatus = 'OPEN'
    }
    if (this.transactionCodeSummryData.recordStatus === 'C') {
      this.transactionCodeSummryData.recordStatus = 'CLOSED'
    }
    if (this.transactionCodeSummryData.verifiedOnce === 'N') {
      this.transactionCodeSummryData.verifiedOnce = 'NO'
    }
    if (this.transactionCodeSummryData.verifiedOnce === 'Y') {
      this.transactionCodeSummryData.verifiedOnce = 'YES'
    }
  }
  onClickOfAuth() {
    if (this.transactionCodeSummryData.creatorId === this.currentUser) {
      Swal.fire({
        title: 'Maker Cannot Authorized the Record!',
        icon: 'error'
      });
    }
    else {
      this.apiService.onClckOfAuthTransactionCode(this.transactionCodeSummryData.userID, this.currentUser).subscribe(authResp => {
        console.log(authResp);
        this.transactionCodeSummryData = authResp;
        this.auditLog();
        Swal.fire({
          title: 'You Authorized the Record!',
          icon: 'success'
        });
      });

    }
  }
  onClickOfClose() {
    this.apiService.onclickOfCloseTransactionCode(this.transactionCodeSummryData.userID, this.currentUser).subscribe(closeResp => {
      console.log(closeResp);
      this.transactionCodeSummryData = closeResp;
      this.auditLog();
      this.ref.markForCheck();
      if (this.transactionCodeSummryData) {
        Swal.fire({
          title: 'You Closed the Record!',
          icon: 'success'
        });
      }
      else {
        Swal.fire({
          title: 'Failed to Close the Recored!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });

  }
  onClickOfReopen() {
    this.apiService.onclickOfReopenTransactionCode(this.transactionCodeSummryData.userID, this.currentUser).subscribe(openResp => {
      console.log(openResp);
      this.transactionCodeSummryData = openResp;
      this.auditLog();
      this.ref.markForCheck();
      if (this.transactionCodeSummryData) {
        Swal.fire({
          title: 'You Re-Opened the Record!',
          icon: 'success'
        });
      }
      else {
        Swal.fire({
          title: 'Failed to Reopen the Record!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });

  }
  OndeleteofUser(UserId) {
    console.log("USer", UserId);
    this.apiService.deleteUserData(UserId).subscribe(resp => {
      if (resp == true) {
        Swal.fire({
          title: 'User Deleted Successfully!',
          icon: 'success'
        });
        this.router.navigateByUrl('/system-param-maintenance/transaction-code-summary');
      }
      else {
        Swal.fire({
          title: 'Failed to Delete User Data!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });
  }
  onSubmitofForm(formData, auditData) {
    console.log(this.transactionData, formData)
    this.masterClass.creatorDtStamp = auditData.creatorDtStamp;
    this.masterClass.creatorId = this.currentUser;
    this.masterClass.creatorDtStamp = auditData.creatorDtStamp;
    this.masterClass.creatorId = this.currentUser;
    this.masterClass.modNo = auditData.modNo;
    this.masterClass.recordStatus = auditData.recordStatus;
    this.masterClass.verifiedBy = auditData.verifiedBy;
    this.masterClass.verifiedOnce = auditData.verifiedOnce;
    this.masterClass.verifiedStatus = auditData.verifiedStatus;
    this.masterClass.verifiedTime = auditData.verifiedTime;
    this.masterClass.userId = auditData.userID;
    console.log("this.masterClass",this.masterClass);
    this.apiService.updateAuditData(this.masterClass).subscribe(savetrnres => {
      this.savetrnResponse = savetrnres;
      if (this.savetrnResponse) {
        this.modifyMAster(formData);
        this.disablesubmit = true;
      } else {
        Swal.fire({
          title: 'Unable to Save Data!',
          icon: 'warning'
        });

      }
    });
  }
  modifyMAster(formData) {
    this.transactionData = formData.transactionData;
    console.log("this.trnData", formData,formData.transactionData);
    for(let i=0;i<this.transactionData.length;i++) {
      this.transactionData[i].userId = formData.userId;
      this.transactionData[i].creatorDtStamp = formData.creatorDtStamp;
      this.transactionData[i].recordStatus = formData.recordStatus;
      this.transactionData[i].verifiedBy = formData.verifiedBy;
      this.transactionData[i].verifiedOnce = formData.verifiedOnce;
      this.transactionData[i].verifiedStatus = formData.verifiedStatus;
      this.transactionData[i].verifiedTime = formData.verifiedTime;
      this.transactionData[i].creatorId = formData.creatorId;
    }
    this.apiService.updateTransactionCode(this.transactionData, this.currentUser).subscribe(savetrnres => {
      this.updatetrnResp = savetrnres;
      if (this.updatetrnResp) {
        Swal.fire({
          title: 'Data Updated Successfully!',
          icon: 'success'
        });
        
      } else {
        Swal.fire({
          title: 'Failed to Update the Record!',
          icon: 'error'
        });
      }
    });
  }
}
export class TrnData {
  id;
  trnCode;
  trnDesc;
  userId;
  verifiedBy: string;
  verifiedTime: any;
  recordStatus: string;
  verifiedOnce: string;
  modNo: number;
  verifiedStatus: string;
  creatorDtStamp: any;
  creatorId: string;
}
export class masterClass {
  id;
  trnCode;
  trnDesc;
  userId;
  verifiedBy: string;
  verifiedTime: any;
  recordStatus: string;
  verifiedOnce: string;
  modNo: number;
  verifiedStatus: string;
  creatorDtStamp: any;
  creatorId: string;
}

